var earliestFinishTime = function(landStartTime, landDuration, waterStartTime, waterDuration) {
    let m = landStartTime.length;
    let n = waterStartTime.length;
    let res = Infinity;

    let minl = Infinity;
    for (let i = 0; i < m; i++) {
